function RuneIconNew:ApplyIconUI()
	BaseIconNew.ApplyIconUI(self)

	self:SetIcon(self._displayShowIcon)
	self:SetIconBg(self._displayShowIconBg)

	self:UpdateLevel()
	self:UpdateLockUI()
	self:UpdateStarUI()
	self:UpdateLimitIcon()
