-----------------------------------------------------------------
function RuneIconNew:OnInitTrans()
	local iconInst = self._iconInst
	self._uiUnLockTrans = CS.FindTrans(iconInst,"UnLock")
	self._uiUnLockTxtTrans = CS.FindTrans(iconInst,"UnLockTxt")
	self._uiLevelTrans = CS.FindTrans(iconInst,"Level")
	self._uiStarTrans = CS.FindTrans(iconInst,"StarList")
	self._uiLimitIconTrans = CS.FindTrans(iconInst,"LimitIcon")
	self._uiIconBgTrans= CS.FindTrans(iconInst,"IconBg")
	
	CS.ShowObject(self._uiIconBgTrans, true)
	self:InitStartList()
end

-----------------------------------------------------------------
function RuneIconNew:SetLock(b, txt)
	self._showLock = b
	self._lockTxt = txt
end

function RuneIconNew:ShowLock(b,txt)
	self._showLock = b
	self._lockTxt = txt

	if not self:IsIconValid() then return end
	self:UpdateLockUI()
end

function RuneIconNew:UpdateLockUI()
	local b = self._showLock and self._showLock or false
	if self._uiUnLockTrans.gameObject.activeSelf ~= b then
		CS.ShowObject(self._uiUnLockTrans, b)
	end

	if not b then return end

	self:SetXUIText(self._uiUnLockTxtTrans,self._lockTxt or "")
end

function RuneIconNew:UpdateLevel()
	local levelRefId = self._levelRefId
	local level = self._level
	local levelStr = ""
	if levelRefId and level then
		levelStr = "+" .. level
	end
	local refId = self._refId
	local runeRef = self:GetRunRef(refId)
	if runeRef then
		local quenching = runeRef.quenching
		if quenching == 0 then
			levelStr = ""
		end
	end
	self:SetXUIText(self._uiLevelTrans,levelStr)
end

function RuneIconNew:UpdateLimitIcon()
	local displayLimitIcon = self._displayLimitIcon
	if string.isempty(displayLimitIcon) then
		if self._uiLimitIconTrans.gameObject.activeSelf then
			CS.ShowObject(self._uiLimitIconTrans,false)
		end
	else
		self:SetCommonImg(self._uiLimitIconTrans,displayLimitIcon)
		if not self._uiLimitIconTrans.gameObject.activeSelf then
			CS.ShowObject(self._uiLimitIconTrans,true)
		end
	end
end

