function RuneIconNew:SetRuneData(runeData)
	self._id = runeData.id
	self._playerId = runeData.playerId
	self._refId = runeData.refId
	self._heroId = runeData.heroId
	self._skillId = runeData.skillId or {}
	self._attrId = runeData.attrId or {}
	self._recast = runeData.recast
	self._nextSkillId = runeData.nextSkillId or {}
	self._nextAttrId = runeData.nextAttrId or {}
	self._levelRefId = runeData.levelRefId
	self._clazzRefId = runeData.clazzRefId
	self._limitId = runeData.limitId
	self:InitInfo()
end

function RuneIconNew:SetData(refId)
	self._refId = refId
	self:InitInfo()
end

function RuneIconNew:InitInfo()
	local refId = self._refId

	local runeRef = self:GetRunRef(refId)
	local iconPath = nil
	local iconBgPath = nil
	local itemName = nil
	local itemColor = nil
	local limitId = self._limitId
	local star = 0
	local limitIcon = nil
	if runeRef then
		iconPath = runeRef.icon

		if limitId and limitId > 0 then
			local nameOther = string.split(ccLngText(runeRef.nameOther),";")
			if #nameOther > 0 then
				local isUse = false
				for i,v in ipairs(nameOther) do
					v = string.split(v,"=")
					if tonumber(v[1]) == limitId then
						isUse = true
						itemName = v[2]
						limitIcon = v[3]
					end
				end
				if not isUse then
					itemName = ccLngText(runeRef.name)
				end
			else
				itemName = ccLngText(runeRef.name)
			end
		else
			itemName = ccLngText(runeRef.name)
		end

		local quality = runeRef.quality
		local qualityRef = self:GetItemQualityRef(quality)
		if qualityRef then
			iconBgPath = qualityRef.iconBg

			local color = qualityRef.nameColor
			if color then
				itemColor = LUtil.ColorByHex(color)
			end
		end
		star = runeRef.showStar
	end
	local level = 0
	local clazzRefId = self._clazzRefId
	if clazzRefId then
		local ref = self:GetRuneQuenchingRef(clazzRefId)
		if ref then
			level = ref.runeClass
		end
	end
	self._level = level

	if string.isempty(iconPath) then
		iconPath = "rune_bg_4"
	end

	if string.isempty(iconBgPath) then
		iconBgPath = "public_item_bg_1"
	end

	self._displayStar = star
	self._displayShowIcon = iconPath
	self._displayShowIconBg = iconBgPath
	self._displayName = itemName
	self._displayColor = itemColor
	self._displayLimitIcon = limitIcon
end

function RuneIconNew:GetNameData()
	return self._displayName,self._displayColor
end

function RuneIconNew:EnableShowBg(bShow)
	CS.ShowObject(self._uiIconBgTrans, bShow)

end
-----------------------------------------------------------------
function RuneIconNew:GetRunRef(refId)
	return GameTable.MagicRuneRef[refId]
end

function RuneIconNew:GetRuneQuenchingRef(refId)
	return GameTable.MagicRuneQuenchingClassRef[refId]
end
-----------------------------------------------------------------

return RuneIconNew
